import { z } from 'zod';

import { storage } from './base';

export const AccountInfo = z.object({
  userId: z.number(),
  bizId: z.number(),
  avatarUrl: z.string().optional(),
  accountType: z.number(),
  accountId: z.string(),
  channel: z.enum(['webplugin']),
  isFirstLogin: z.boolean(),
  encodedUserName: z.string(),
  mpAvatarUrl: z.string().optional(),
});

export type AccountInfoType = z.infer<typeof AccountInfo> | null;

const setAccountInfo = (accountInfo: AccountInfoType) => storage.set({ accountInfo });

/* 登出时使用 */
const clearAccountInfo = () => storage.remove('accountInfo');

const getAccountInfo = async () => {
  const result = await storage.get('accountInfo');
  return (result.accountInfo ?? null) as AccountInfoType;
};

export const account = {
  set: setAccountInfo,
  get: getAccountInfo,
  clear: clearAccountInfo,
};
