import { BACKGROUND_MESSAGE_TYPES, CONTENT_MESSAGE_TYPES, pointData } from '@/constants';
import { getGlobalConfig } from '@/extends';
import storage from '@/libs/storage';

import {
  chat,
  chooseDesktopMedia,
  extractToNote,
  offscreen,
  openNewTab,
  request,
} from '../messageHandlers';

import { onSetup } from './tabs';

export const onInstalled = (details: chrome.runtime.InstalledDetails) => {
  storage.baseStorage.set({ onInstalled: 1 });
  const { sessionSyncUrl } = getGlobalConfig().getEnvInfo();
  // 同步登录态
  if (details.reason === 'update') {
    fetch(sessionSyncUrl).catch(() => console.error('Session sync failed'));
  }
  onSetup();
};

export const onUpdateAvailable = async () => {
  const tab = await browser.tabs.query({ active: true, currentWindow: true });
  if (!tab[0].id) return;
  messenger.sendMessageToTab(tab[0].id, {
    type: CONTENT_MESSAGE_TYPES.sendUpgrade,
  });
};

/**
 * onMessage 作为 listener 必须是 sync 的
 * 因此必须使用 then 形式来调用 sendResponse
 */
export const onMessage: (
  message: { type: BACKGROUND_MESSAGE_TYPES; payload: any },
  sender: chrome.runtime.MessageSender,
  sendResponse: (response: any) => void,
) => void = (message, sender, sendResponse) => {
  const { type } = message;
  logger.success('Received message from content:', type, message);

  switch (type) {
    case BACKGROUND_MESSAGE_TYPES.request:
      request({ type: BACKGROUND_MESSAGE_TYPES.request, payload: message.payload })
        .then((res) => {
          sendResponse(res);
        })
        .catch((e) => sendResponse({ success: false, error: e.message }));
      /* 对于需要回传 response 的异步方法，需要显示 return true 以保持 message port */
      return true;
    case BACKGROUND_MESSAGE_TYPES.chatSse:
    case BACKGROUND_MESSAGE_TYPES.stopChat:
      return chat(message);
    case BACKGROUND_MESSAGE_TYPES.chooseDesktopMedia:
      return chooseDesktopMedia(message, sender);
    case BACKGROUND_MESSAGE_TYPES.extractToNote:
      return extractToNote(message);
    case BACKGROUND_MESSAGE_TYPES.openNewTab:
      return openNewTab(message);
    case BACKGROUND_MESSAGE_TYPES.offscreen:
      if (pointData.includes(message.payload.type)) {
        return true;
      }
      return offscreen(message);
    default:
      return Promise.resolve();
  }
};
