import { type BACKGROUND_MESSAGE_TYPES } from '@/constants';
import request, { type FetchRequest } from '@/libs/request';

const onRequest = async (message: {
  type: BACKGROUND_MESSAGE_TYPES.request;
  payload: FetchRequest;
}) => {
  const { payload } = message;
  const responseRaw = await request(payload);
  const response = await responseRaw.json();

  return response;
};

export default onRequest;
