export const randomTraceId = (len = 32) => {
  // 16位16进制字符
  const digits = '0123456789abcdef';
  let n = '';
  for (let i = 0; i < len; i += 1) {
    const rand = Math.floor(Math.random() * digits.length);
    n += digits[rand];
  }
  return n;
}

//切割简化 api, 取 关键值
export const cutApiFn = (api: string) => {
  return api.includes('/api/') && api.split('/api/')[1] || 'Illegal Api';
}

// 封装http请求, 根据项目 支持 get
export const httpRequest = (method: string, url: string) => {
  return new Promise((resolve, reject) => {
    let xhr = new XMLHttpRequest();
    xhr.responseType = 'json';// 指定返回类型

    xhr.onreadystatechange = () => {
      switch (xhr.status) {
        case 200: 
        resolve(xhr.response);
        break;
        default: 
        resolve({status: xhr.status, res: xhr.response, content: false});
      }
    };
    xhr.open(method, url, true);
    xhr.setRequestHeader('Content-type', 'application/json, text/plain, */*');
    xhr.send(null);
});
}

export const getBrowserType = () => {
  let browserName = '';
  if (navigator.userAgent.indexOf("Chrome") !== -1) {
      if (navigator.userAgent.indexOf("Edg") !== -1) {
          browserName = "Edge";
      } else {
          browserName = "Chrome";
      }
  };

  return browserName;
};

export const sleep = (time: number) => {
  return new Promise(resolve => setTimeout(() => resolve(true), time));
}

/**
 * @description: 字符串转成txt文件
 * @param { string } content 文本内容
 * @returns { File } 文件
 */
export const stringToFile = (content: string, fileName = 'html.txt'): File => {
  const blob = new Blob([content], { type: 'text/plain' });
  const file = new File([blob], fileName, { type: 'text/plain' });
  return file;
};