export const ensureOffscreenDocument = async () => {
  const page = 'offscreen.html';

  const existing = await browser.offscreen.hasDocument();
  if (existing) {
    return;
  }

  await browser.offscreen.createDocument({
    url: page,
    reasons: [browser.offscreen.Reason.WORKERS],
    justification: 'Needed for web worker',
  });
};

export default async (message: any) => {
  await ensureOffscreenDocument();
  const { type, payload } = message.payload;
  messenger.sendMessageToOffscreen({ type, payload });
};
