import { BACKGROUND_MESSAGE_TYPES } from '@/constants';
import request, { type FetchRequest } from '@/libs/request';
import messenger from '@/utils/messenger';

interface TRequestMessagePayload<P> extends FetchRequest {
  params?: P;
}

type TRequestMessage<P> = {
  type: BACKGROUND_MESSAGE_TYPES.request;
  payload: TRequestMessagePayload<P>;
};

type TResponse<R> = {
  success: true;
  code: 200;
  data: R;
  traceId: string;
  failed: false;
};

export enum METHOD {
  get = 'get',
  post = 'post',
}

const fetcher = async <P, R>(req: TRequestMessagePayload<P>): Promise<TResponse<R>> => {
  const message: TRequestMessage<P> = {
    type: BACKGROUND_MESSAGE_TYPES.request,
    payload: req,
  };

  try {
    const response = await messenger.sendMessageToBackgroundAsync<TRequestMessage<P>, TResponse<R>>(
      message,
    );
    return response;
  } catch (error: any) {
    return error;
  }
};

class Service {
  private apiPrefix: string;

  constructor(apiPrefix: string) {
    if (import.meta.env.VITE_REACT_APP_SERVER_ENV === 'pre') {
      if (apiPrefix.startsWith('http://') || apiPrefix.startsWith('https://')) {
        const [protocol, rest] = apiPrefix.split('://');
        this.apiPrefix = `${protocol}://pre-${rest}`;
      } else {
        this.apiPrefix = `pre-${apiPrefix}`;
      }
    } else {
      this.apiPrefix = apiPrefix;
    }
  }

  async get<P, R>(url: string, params?: P): Promise<TResponse<R>> {
    try {
      const response = await fetcher<P, R>({
        method: 'get',
        api: `${this.apiPrefix}${url}`,
        params,
      });
      return response as TResponse<R>;
    } catch (error) {
      this.handleException(error);
      throw error;
    }
  }

  async post<P, R>(url: string, params?: P): Promise<TResponse<R>> {
    try {
      const response = await fetcher<P, R>({
        method: 'post',
        api: `${this.apiPrefix}${url}`,
        params,
      });
      return response as TResponse<R>;
    } catch (error) {
      this.handleException(error);
      throw error;
    }
  }

  async getFromBackground<P, R>(url: string, params?: P): Promise<Response> {
    try {
      const response = (await request({
        method: 'get',
        api: `${this.apiPrefix}${url}`,
        params,
      })) as unknown as Response;
      return response;
    } catch (error) {
      this.handleException(error);
      throw error;
    }
  }

  async postFromBackground<P, R>(url: string, params?: P): Promise<Response> {
    try {
      const response = (await request({
        method: 'post',
        api: `${this.apiPrefix}${url}`,
        params,
      })) as unknown as Response;
      return response;
    } catch (error) {
      this.handleException(error);
      throw error;
    }
  }

  serviceFactory<P, R>(path: string, method: METHOD): (params?: P) => Promise<TResponse<R>>;
  serviceFactory<P, R>(
    path: string,
    method: METHOD,
    customParams: (params: any) => P,
  ): (params?: any) => Promise<TResponse<R>>;
  serviceFactory<P, R>(path: string, method: METHOD, customParams?: (params: any) => P) {
    return (params?: any): Promise<TResponse<R>> => {
      const finalParams = customParams ? customParams(params) : params;
      switch (method) {
        case METHOD.get:
          return this.get<P, R>(path, finalParams);
        case METHOD.post:
          return this.post<P, R>(path, finalParams);
        default:
          throw new Error(`不支持的请求方法: ${method}`);
      }
    };
  }

  private handleException(error: any) {
    // 高扩展性的异常处理
    logger.error('Service Error:', error);
    // 可以在这里添加更多的异常处理逻辑
  }
}

export default Service;
