import { isEmpty } from 'lodash-es';
import { type Tabs } from 'wxt/browser';

import { CODE_NOT_LOGIN } from '@/constants';
import storage from '@/libs/storage';
import { initPluginConfig } from '@/libs/storage/pluginStorage';
import { API_PREFIX } from '@/services';
import Service from '@/services/service';

const service = new Service(API_PREFIX.qianwenAssistant);

const checkLogin = async () => {
  const result = await service.getFromBackground('/user/info/get');

  if (result.ok) {
    const { data, success, errorCode } = await result.json();
    if (!success && errorCode === CODE_NOT_LOGIN) {
      storage.account.set(null);
    } else {
      storage.account.set(data);
    }

  }
};

const getPluginConfig = async () => {
  const result = await service.getFromBackground('/plug/config/get');

  if (result.ok) {
    const { success, data } = (await result.json()) || {};
    if (success) {
      let { tingwuConfig, zhiwenConfig } = data || {};
      tingwuConfig = JSON.parse(tingwuConfig || '{}');
      zhiwenConfig = JSON.parse(zhiwenConfig || '{}');
      const initTingwuConfig = initPluginConfig.tingwuConfig;
      const initZhiwenConfig = initPluginConfig.zhiwenConfig;
      storage.pluginStorage.set({
        tingwuConfig: isEmpty(tingwuConfig)
          ? initTingwuConfig
          : { ...initTingwuConfig, ...tingwuConfig },
        zhiwenConfig: isEmpty(zhiwenConfig)
          ? initZhiwenConfig
          : { ...initZhiwenConfig, ...zhiwenConfig },
      });
    }
  }
};

export const processedTabs: Record<number, boolean> = {};

const setup = (activeInfo: Tabs.OnActivatedActiveInfoType) => {
  if (processedTabs[activeInfo.tabId]) {
    return; // Skip if already processed
  }
  browser.tabs.get(activeInfo.tabId, (tab) => {
    if (tab.url?.startsWith('http://') || tab.url?.startsWith('https://')) {
      const scripts = browser.runtime.getManifest().content_scripts ?? [];
      for (const script of scripts) {
        const { js = [], css = [], all_frames } = script;
        const target = { tabId: tab.id!, allFrames: all_frames };
        if (js.length) {
          browser.scripting.executeScript({
            files: js,
            injectImmediately: true,
            target,
          });
        }
        if (css.length) {
          browser.scripting.insertCSS({
            files: css,
            target,
          });
        }
        processedTabs[activeInfo.tabId] = true;
      }
    }
  });
};

export const onSetup = () => {
  browser.tabs.onActivated.addListener(setup);
};

export const onActivated = () => {
  checkLogin();
  getPluginConfig();
};
