/**
 * 正则匹配时，转义特殊字符
 * @param str 
 * @returns 
 */
export const escapeRegExp = (str: string) => str.replace(/[.*+?${}()|[\]\\]/g, '\\$&');  // $&表示整个匹配的字符串
