import { fetchEventSource } from '@microsoft/fetch-event-source';
import { v4 as uuid } from 'uuid';

import { BACKGROUND_MESSAGE_TYPES, CONTENT_MESSAGE_TYPES } from '@/constants';
import { getGlobalConfig } from '@/extends';

export default async (message: any) => {
  const {
    type,
    payload: { params, url, taskStatus },
  } = message;
  let sseId = '';
  const sseController = new AbortController();
  const tab = await getCurrentTab();

  if (type === BACKGROUND_MESSAGE_TYPES.chatSse) {
    const currentTab = await getCurrentTab(url);
    const { docChatApiPrefix } = getGlobalConfig().getEnvInfo();
    // 对话sse接口
    sseId = params.sseId;
    let sseUrl = '';
    if (taskStatus === 'success') {
      sseUrl = `${docChatApiPrefix}/doc_chat`;
    } else {
      sseUrl = `${docChatApiPrefix}/doc_chat_in_parsing`;
    }

    const close = () => {
      if (sseController?.signal?.aborted) sseController.abort();
    };

    if (!globalThis.window) {
      globalThis.window = {
        fetch: globalThis.fetch,
        setTimeout: (fn, timeout) => globalThis.setTimeout(fn, timeout),
        clearTimeout: (t) => globalThis.clearTimeout(t),
      };
    }
    if (!globalThis.document) {
      globalThis.document = { removeEventListener: () => {} };
    }

    fetchEventSource(sseUrl, {
      credentials: 'include',
      method: 'POST',
      openWhenHidden: true,
      signal: sseController.signal,
      headers: {
        'message-id': uuid(),
        timeout: '12000',
        'Content-Type': 'application/json',
        token: 'aliyun',
        platform: 'QIANWEN',
      },
      body: JSON.stringify({
        ...params,
        source: 'efficiency',
      }),
      onmessage: (resp) => {
        const { data = {} } = JSON.parse(resp.data) || {};
        if (data.stop_reason === 'stop') {
          close();
        }
        messenger.sendMessageToTab(tab?.id || currentTab?.id, {
          type: CONTENT_MESSAGE_TYPES.sseOutput,
          payload: {
            ...data,
            sseId,
            status: data.stop_reason === 'stop' ? 'stop' : 'streaming',
          },
        });
      },
      onerror: (error) => {
        messenger.sendMessageToTab(tab?.id || currentTab?.id, {
          type: CONTENT_MESSAGE_TYPES.sseOutput,
          payload: { status: 'error', sseId },
        });
        close();
        throw error;
      },
    });
    return true;
  }

  if (type === BACKGROUND_MESSAGE_TYPES.stopChat) {
    if (sseController.signal?.aborted) sseController.abort();

    return true;
  }
};
