import { CONTENT_MESSAGE_TYPES } from '@/constants';
import { getGlobalConfig } from '@/extends';

export default async (message: any) => {
  /* 获取到摘录内容后,创建效率笔记tab并发送摘录内容给新tab */
  const {
    payload: { content, taskId },
  } = message;
  const { efficiencyUrl } = getGlobalConfig().getEnvInfo();

  const noteUrl = `${efficiencyUrl}doc/read?taskId=${taskId}`;
  const existedTab = await browser.tabs.query({ url: noteUrl });

  let tabId: number;

  if (existedTab && existedTab.length > 0) {
    tabId = existedTab[0].id!;
    const windowId = existedTab[0]?.windowId;
    browser.windows.update(windowId, { focused: true }, () => {
      browser.tabs.update(tabId, { active: true });
    });
  } else {
    const newTab = await browser.tabs.create({
      url: noteUrl,
    });

    tabId = newTab.id!;
  }

  if (tabId) {
    messenger.sendMessageToTab(
      tabId,
      {
        type: CONTENT_MESSAGE_TYPES.deliverExtraction,
        payload: content,
      },
      (response) => {
        if (response === 'failed') {
          /* 异常处理 */
          logger.error('Message sent to tab successfully but response status is failed', response);
        }
      },
    );
  }
};
