export const getCurrentTab = (url?: string): Promise<browser.tabs.Tab> => {
  return new Promise((resolve) => {
    const queryInfo = url ? { url } : { active: true, currentWindow: true };
    browser.tabs.query(queryInfo, (tabs) => {
      const tab = tabs?.[0];
      if (tab) {
        resolve(tab);
      } else {
        // 如果获取不到，兜底获取 active tab
        browser.tabs.query({ active: true, currentWindow: true }, (activeTabs) => {
          resolve(activeTabs[0]);
        });
      }
    });
  });
}
