import { CONTENT_MESSAGE_TYPES } from '@/constants';

export default async (message: any, sender: chrome.runtime.MessageSender) => {
  const { enableMicphone, filename, dirId, sourceLanguage, transTargetValue, translateSwitch } =
    message.payload;

  const tab = (await getCurrentTab()) || (await sender.tab?.id);

  browser.desktopCapture.chooseDesktopMedia(['tab', 'audio'], tab, async (streamId, options) => {
    if (!tab.id) {
      return;
    }

    messenger.sendMessageToTab(tab.id, {
      type: CONTENT_MESSAGE_TYPES.desktopCapture,
      payload: {
        streamId,
        options,
        enableMicphone,
        filename,
        dirId,
        sourceLanguage,
        transTargetValue,
        translateSwitch,
      },
    });
  });
};
