import { BACKGROUND_MESSAGE_TYPES } from '@/constants';

interface SendTabMessageOptions {
  /* 最大重试发送次数*/
  retry?: number;
  /* 重试间隔 */
  interval?: number;
}

const DEFAULT_RETRY = 10;
const DEFAULT_INTERVAL = 500;

const sendMessageToTab = (
  tabId: number,
  message: any,
  responseCallback?: (response: any) => void,
  options: SendTabMessageOptions = {},
) => {
  let { retry: _retry = DEFAULT_RETRY } = options;
  const { interval = DEFAULT_INTERVAL } = options;
  let _time: any = null;
  const send = () => {
    if (!responseCallback || !(responseCallback instanceof Function)) {
      /* 未传入 responseCallback 的时候不应该传入 onResponse 这个回调 */
      /**
       * 未传入 responseCallback 即单工通信不关心回复，不需要重试
       * 这时也不应该给 tabs.sendMessage 传入 responseCallback 回调
       */
      logger.info(
        `Sending message to tab, ignores response;`,
        message.type,
        message.payload,
        tabId,
      );
      browser.tabs.sendMessage(tabId, message);
    } else {
      logger.info(
        `Sending message to tab; Attempt: ${_retry};`,
        message.type,
        message.payload,
        tabId,
      );
      browser.tabs.sendMessage(tabId, message, (response) => {
        if (response) {
          responseCallback(response);
          return;
        } else if (_retry > 0) {
          logger.error(response);
          _retry -= 1;
          if (_time) {
            clearTimeout(_time);
          }
          _time = setTimeout(send, interval);
        } else {
          throw new Error('Message send to tab failed:', message);
        }
      });
    }
  };

  /* leading send立即触发, 否则用户会觉得卡顿 */
  send();
};

const sendMessageToBackground = (...arg: any) => {
  try {
    browser.runtime.sendMessage(...arg);
  } catch (error) {
    return;
  }
};

/**
 * 返回 Promise 的 sendMessageToBackground
 * 主要用于接口请求，即BACKGROUND_MESSAGE_TYPES.request
 * 如有其他场景也需要使用，需要改造 background 侧 listener
 * 参考src/entrypoints/background/scope/runtime.ts line:41
 */
const sendMessageToBackgroundAsync: <P = any, R = unknown>(message: P) => Promise<R> = (
  message,
) => {
  return new Promise((resolve, reject) => {
    logger.info('Sending message to background, expect async response:', message);
    sendMessageToBackground(message, (response) => {
      if (response instanceof Error) {
        reject(response);
      } else {
        resolve(response);
      }
    });
  });
};

const sendMessageToOffscreen = ({
  type,
  payload,
  fn,
}: {
  type: string;
  payload: any;
  fn?: any;
}) => {
  logger.info('Sending message to offscreen:', type, payload);
  sendMessageToBackground(
    {
      type: BACKGROUND_MESSAGE_TYPES.offscreen,
      payload: {
        type,
        payload,
      },
    },
    fn,
  );
};

const messenger = {
  sendMessageToTab,
  sendMessageToBackground,
  sendMessageToBackgroundAsync,
  sendMessageToOffscreen,
};
export default messenger;
