import dayjs from 'dayjs';

import { storage } from './base';

export interface TingWuConfigType {
  enabledMicphone: boolean;
  sourceLanguage: string;
  targetLanguage: string;
  saveAs: string;
  filename: string;
  tabChecked: boolean; //当前tab是否被选择
}
export interface ZhiwenConfigType {
  showType: 'sidebar' | 'floatWindow';
  isSelect: boolean;
  floatButton: boolean;
  tabChecked: boolean; //当前tab是否被选择
}

export interface PluginConfigType {
  tingwuConfig: TingWuConfigType;
  zhiwenConfig: ZhiwenConfigType;
}

export const initPluginConfig: PluginConfigType = {
  tingwuConfig: {
    enabledMicphone: false,
    sourceLanguage: 'cn',
    targetLanguage: '',
    saveAs: '0',
    filename: dayjs().format('YYYY-MM-DD HH:mm 记录'),
    tabChecked: false,
  },
  zhiwenConfig: {
    showType: 'floatWindow',
    isSelect: true,
    floatButton: true,
    tabChecked: true,
  },
};

const setPluginConfig = (pluginConfig: PluginConfigType) => storage.set({ pluginConfig });

const clearPluginConfig = () => storage.remove('pluginConfig');

const getPluginConfig = async () => {
  const result = await storage.get('pluginConfig');
  return (result?.pluginConfig || initPluginConfig) as PluginConfigType;
};

const getZhiwenConfig = async () => {
  const result = await storage.get('pluginConfig');
  return (result?.pluginConfig?.zhiwenConfig || initPluginConfig.zhiwenConfig) as ZhiwenConfigType;
};

const getTingwuConfig = async () => {
  const result = await storage.get('pluginConfig');
  return (result?.pluginConfig?.tingwuConfig || initPluginConfig.tingwuConfig) as TingWuConfigType;
};

export const pluginStorage = {
  set: setPluginConfig,
  get: getPluginConfig,
  clear: clearPluginConfig,
  getZhiwenConfig,
  getTingwuConfig,
};
