import { atebBasicConfig, extPreBasicConfig } from './atebBasicConfig';
import { extPublicServerConfig } from './extPublicServerConfig';

export const createConfig = (serverEnv: string, installMode: string) => {
  const extensions: any[] = [];

  extensions.push(extPublicServerConfig);

  if (serverEnv === 'pre') {
    extensions.push(extPreBasicConfig);
  }

  const result: ReturnType<typeof atebBasicConfig.generate> = extensions
    .reduce((current, next) => {
      return current.extendedBy(next);
    }, atebBasicConfig)
    .generate({});

  return result;
};

const serverEnv = import.meta.env.VITE_REACT_APP_SERVER_ENV || 'prod';
const installMode = import.meta.env.VITE_REACT_APP_INSTALL_MODE || 'store';

const _config = createConfig(serverEnv, installMode);

export const getGlobalConfig = () => {
  return _config;
};
