export interface FetchRequest {
  method: 'get' | 'post';
  api: string;
  params?: any;
}

interface FetchOptions extends RequestInit {
  traceId: string;
  spanId: string;
}

/* 在 background 的 service worker 中执行请求 */
export default async (req: FetchRequest): Promise<Response> => {
  const traceId = randomTraceId(32);
  const spanId = randomTraceId(16);
  const option: FetchOptions = {
    method: req.method,
    headers: {
      'Content-Type': 'application/json',
      Accept: 'application/json, text/plain, */*',
      'X-B3-Sampled': '1',
      'X-B3-TraceId': traceId,
      'X-B3-SpanId': spanId,
      'x-tw-from': 'tongyi',
      platform: 'QIANWEN',
    },
    traceId,
    spanId,
    credentials: 'include',
  };

  const url = new URL(req.api);

  url.searchParams.append('c', 'tongyi-webplugin');

  if (req.method === 'post') {
    option.body = JSON.stringify(req.params);
  } else if (req.method === 'get' && req.params) {
    // 处理 GET 请求参数，确保特殊字符被正确编码
    Object.entries(req.params).forEach(([key, value]) => {
      const encodedKey = encodeURIComponent(key);
      const encodedValue = encodeURIComponent(String(value));
      url.searchParams.append(encodedKey, encodedValue);
    });
  }

  const _url = url.toString();

  return await fetch(_url, option);
};
