import { onClicked } from './scope/action';
import { onEnabled, onUninstalled } from './scope/management';
import { onInstalled, onMessage, onUpdateAvailable } from './scope/runtime';
import { onActivated } from './scope/tabs';
import { ensureOffscreenDocument } from './messageHandlers';

export default defineBackground({
  type: 'module',
  main: () => {
    logger.info(
      'Current server env:',
      import.meta.env.VITE_REACT_APP_SERVER_ENV,
      'Current install mode:',
      import.meta.env.VITE_REACT_APP_INSTALL_MODE,
    );

    ensureOffscreenDocument();

    /* @ts-ignore chrome -> browser */
    browser.action.onClicked.addListener(onClicked);

    /* @ts-ignore chrome -> browser */
    browser.management.onEnabled.addListener(onEnabled);
    browser.management.onUninstalled.addListener(onUninstalled);

    browser.runtime.onInstalled.addListener(onInstalled);
    browser.runtime.onMessage.addListener(onMessage);
    browser.runtime.onUpdateAvailable.addListener(onUpdateAvailable);

    browser.tabs.onActivated.addListener(onActivated);
  },
});
